import{_ as e,o as r,c as t,aQ as i}from"./chunks/framework.cDvftfeu.js";const u=JSON.parse('{"title":"ユーザーセンター","description":"Hamアカウントと設定の管理。","frontmatter":{"description":"Hamアカウントと設定の管理。"},"headers":[],"relativePath":"ja/handbook/user-center.md","filePath":"ja/handbook/user-center.md","lastUpdated":1777525243000}'),l={name:"ja/handbook/user-center.md"};function o(s,a,h,n,d,c){return r(),t("div",null,[...a[0]||(a[0]=[i('<h1 id="ユーザーセンター" tabindex="-1">ユーザーセンター <a class="header-anchor" href="#ユーザーセンター" aria-label="Permalink to &quot;ユーザーセンター&quot;">​</a></h1><p>Hamアカウントにログインすると、ユーザーセンターでアカウント情報や設定を管理できます。</p><h2 id="hamアカウント" tabindex="-1">Hamアカウント <a class="header-anchor" href="#hamアカウント" aria-label="Permalink to &quot;Hamアカウント&quot;">​</a></h2><p>Hamは以下のログイン方法に対応しています：</p><ul><li>Passkey</li><li>QQ</li><li>WeChat</li><li>GitHub</li><li>自強Auth</li><li>Appleサインイン（iOSのみ）</li></ul><h2 id="プロフィール" tabindex="-1">プロフィール <a class="header-anchor" href="#プロフィール" aria-label="Permalink to &quot;プロフィール&quot;">​</a></h2><p>ログイン後、ユーザーセンターでアバターやニックネームを変更できます。</p><h2 id="ログイン端末" tabindex="-1">ログイン端末 <a class="header-anchor" href="#ログイン端末" aria-label="Permalink to &quot;ログイン端末&quot;">​</a></h2><p>現在ログインしている端末の一覧を確認し、使用しなくなった端末を削除できます。</p><h2 id="ソーシャルアカウント" tabindex="-1">ソーシャルアカウント <a class="header-anchor" href="#ソーシャルアカウント" aria-label="Permalink to &quot;ソーシャルアカウント&quot;">​</a></h2><p>連携済みのソーシャルアカウントを確認したり、新しいアカウントを連携したり、既存のアカウントの連携を解除したりできます。対応するソーシャルアカウントの種類はログイン方法と同じです。</p><h2 id="passkey管理" tabindex="-1">Passkey管理 <a class="header-anchor" href="#passkey管理" aria-label="Permalink to &quot;Passkey管理&quot;">​</a></h2><p>ここでPasskeyを管理できます。新しいPasskeyの追加や既存のPasskeyの削除が可能です。Passkeyはパスワード不要のログイン方法で、端末の生体認証（Face IDや指紋など）を使用して本人確認を行います。</p><h2 id="qrコードログイン" tabindex="-1">QRコードログイン <a class="header-anchor" href="#qrコードログイン" aria-label="Permalink to &quot;QRコードログイン&quot;">​</a></h2><p>アプリを使ってHam WebのログインQRコードをスキャンし、素早くログインできます。</p><h2 id="認可済みアプリ" tabindex="-1">認可済みアプリ <a class="header-anchor" href="#認可済みアプリ" aria-label="Permalink to &quot;認可済みアプリ&quot;">​</a></h2><p>Hamアカウントでログイン認可した第三者アプリを確認・管理できます。使用しなくなったアプリの認可を取り消すことも可能です。</p><h2 id="その他" tabindex="-1">その他 <a class="header-anchor" href="#その他" aria-label="Permalink to &quot;その他&quot;">​</a></h2><p>「その他」では、アカウントの退会などの操作が行えます。</p>',19)])])}const m=e(l,[["render",o]]);export{u as __pageData,m as default};
